const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const triggerItem = $('Gmail Trigger').itemMatching(i);
  const binary = (triggerItem && triggerItem.binary) || {};
  const keys = Object.keys(binary).filter(function (k) { return k.indexOf('attachment_') === 0; });
  for (let j = 0; j < keys.length; j++) {
    const key = keys[j];
    out.push({
      json: {
        gmail_message_id: triggerItem.json.id,
        gmail_link: 'https://mail.google.com/mail/u/0/#inbox/' + triggerItem.json.id,
        email_date: triggerItem.json.date,
        subject: triggerItem.json.subject
      },
      binary: { data: binary[key] }
    });
  }
}
return out;

const items = $input.all();
const out = [];
const VALID_EXT = ['pdf', 'jpg', 'jpeg', 'png'];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const context = $('Split Attachments').itemMatching(i).json;
  const binary = item.binary || {};
  const keys = Object.keys(binary).filter(function (k) { return k.indexOf('file_') === 0; });

  let found = 0;
  for (let j = 0; j < keys.length; j++) {
    const key = keys[j];
    const b = binary[key];
    const fileName = (b.fileName || key || '').toLowerCase();
    const ext = (b.fileExtension || fileName.split('.').pop() || '').toLowerCase();
    if (VALID_EXT.indexOf(ext) === -1) continue;
    found++;
    out.push({
      json: {
        gmail_message_id: context.gmail_message_id,
        gmail_link: context.gmail_link,
        email_date: context.email_date,
        subject: context.subject,
        ready_for_extraction: true
      },
      binary: { data: b }
    });
  }

  if (found === 0) {
    out.push({
      json: {
        ready_for_extraction: false,
        email_date: context.email_date || '',
        branch: 'Unknown',
        supplier: '',
        account_no: '',
        statement_date: '',
        current: 0, d30: 0, d60: 0, d90: 0, d120plus: 0, total: 0,
        currency: '',
        status: 'Needs Manual',
        confidence: 0,
        notes: 'zip archive contained no extractable PDF/JPG/PNG files',
        gmail_link: context.gmail_link || ''
      }
    });
  }
}

return out;

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
$input.item.json.pdfBase64 = buffer.toString('base64');
$input.item.json.mimeType = ($input.item.binary && $input.item.binary.data && $input.item.binary.data.mimeType) || 'application/pdf';
return $input.item;

