const upstream = $('Prepare Base64').itemMatching($itemIndex).json;
const KNOWN_BRANCHES = ['Dunnottar Hardware', 'Selcourt Hardware', 'Eastvale Hardware'];
const CONFIDENCE_FLOOR = 0.75;

let raw = '';
try {
  raw = ($json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) || '';
} catch (e) { raw = ''; }
raw = raw.trim().replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/```\s*$/, '');

let parsed = null;
try { parsed = JSON.parse(raw); } catch (e) { parsed = null; }

function normNum(v) { const n = parseFloat(v); return isNaN(n) ? 0 : n; }

if (!parsed) {
  return { json: { email_date: upstream.email_date || '', branch: 'Unknown', supplier: '', account_no: '', statement_date: '', current: 0, d30: 0, d60: 0, d90: 0, d120plus: 0, total: 0, currency: '', status: 'Needs Manual', confidence: 0, notes: 'extraction response was not valid JSON', gmail_link: upstream.gmail_link || '' } };
}

let branch = (parsed.branch || '').trim();
let matchedBranch = null;
for (let i = 0; i < KNOWN_BRANCHES.length; i++) {
  if (KNOWN_BRANCHES[i].toLowerCase() === branch.toLowerCase()) { matchedBranch = KNOWN_BRANCHES[i]; break; }
}
if (!matchedBranch) {
  for (let i = 0; i < KNOWN_BRANCHES.length; i++) {
    if (branch && (KNOWN_BRANCHES[i].toLowerCase().indexOf(branch.toLowerCase()) !== -1 || branch.toLowerCase().indexOf(KNOWN_BRANCHES[i].toLowerCase()) !== -1)) { matchedBranch = KNOWN_BRANCHES[i]; break; }
  }
}
const finalBranch = matchedBranch || 'Unknown';

const current = normNum(parsed.current);
const d30 = normNum(parsed.d30);
const d60 = normNum(parsed.d60);
const d90 = normNum(parsed.d90);
const d120plus = normNum(parsed.d120plus);
const total = normNum(parsed.total);
const sum = current + d30 + d60 + d90 + d120plus;

let confidence = normNum(parsed.confidence);
let notes = parsed.notes || '';

if (Math.abs(sum - total) > 1) { notes = (notes ? notes + '; ' : '') + 'sum mismatch'; confidence = Math.max(0, confidence - 0.2); }

const status = (confidence >= CONFIDENCE_FLOOR && finalBranch !== 'Unknown') ? 'OK' : 'Needs Manual';

return { json: { email_date: upstream.email_date || '', branch: finalBranch, supplier: parsed.supplier || '', account_no: parsed.account_no || '', statement_date: parsed.statement_date || '', current, d30, d60, d90, d120plus, total, currency: parsed.currency || '', status, confidence, notes, gmail_link: upstream.gmail_link || '' } };

